import { useEffect, useState } from "react";
import { useNavigate, useParams } from "react-router-dom";
import { getStaff, updateStaff } from "../../api/adminUserApi";
import { getAuth } from "../../utils/auth";

export default function EditStaff() {
  const { id } = useParams();
  const navigate = useNavigate();

  const { role } = getAuth();
  const isAdmin = role === "admin";

  const [loading, setLoading] = useState(true);
  const [user, setUser] = useState(null);

  const [form, setForm] = useState({
    role: "staff",
    isDeleted: false,
  });

  useEffect(() => {
    const load = async () => {
      try {
        // Backend has only GET /api/admin-users (not /:id)
        // So we fetch all and find by id
        const res = await getStaff();
        const found = (res.data || []).find((u) => u._id === id);

        if (!found) {
          alert("User not found");
          return navigate("/admin/staff");
        }

        setUser(found);
        setForm({
          role: found.role || "staff",
          isDeleted: !!found.isDeleted,
        });
      } catch (err) {
        alert(err.response?.data?.message || "Failed to load user");
        navigate("/admin/staff");
      } finally {
        setLoading(false);
      }
    };

    if (isAdmin) load();
    else setLoading(false);
  }, [id, navigate, isAdmin]);

  const submit = async (e) => {
    e.preventDefault();
    try {
      await updateStaff(id, form);
      alert("Updated!");
      navigate("/admin/staff");
    } catch (err) {
      alert(err.response?.data?.message || "Update failed");
    }
  };

  if (!isAdmin) return <div className="page" style={{ padding: "20px", textAlign: "center", color: "var(--text-light)" }}>Access denied</div>;
  if (loading) return <div className="page" style={{ padding: "20px", textAlign: "center", color: "var(--text-light)" }}>Loading...</div>;

  return (
    <div className="page">
      <div className="pageHead">
        <div>
          <div className="pageTitle">Edit Staff User</div>
          <div className="pageSub">Update role and account status</div>
        </div>
      </div>

      <div className="card cardPad" style={{ maxWidth: 640, margin: "32px auto" }}>
        {user && (
          <div style={{ marginBottom: 24, padding: 16, border: "1px solid var(--border)", borderRadius: "var(--radius)", backgroundColor: "rgba(76, 175, 80, 0.05)" }}>
            <div style={{ marginBottom: 8, fontSize: "14px", color: "var(--text-light)" }}><b>Name:</b> {user.name}</div>
            <div style={{ fontSize: "14px", color: "var(--text-light)" }}><b>Email:</b> {user.email}</div>
          </div>
        )}

        <form onSubmit={submit}>
          <label className="label">Role</label>
          <select
            value={form.role}
            onChange={(e) => setForm((p) => ({ ...p, role: e.target.value }))}
            className="select"
          >
            <option value="staff">Staff</option>
            <option value="manager">Manager</option>
            <option value="admin">Admin</option>
            <option value="user">User</option>
          </select>

          <div style={{ marginTop: 24 }}>
            <label style={{ display: "flex", alignItems: "center", gap: 12, color: "var(--text)", fontSize: "14px", fontWeight: "500", cursor: "pointer" }}>
              <input
                type="checkbox"
                checked={form.isDeleted}
                onChange={(e) => setForm((p) => ({ ...p, isDeleted: e.target.checked }))}
                style={{ cursor: "pointer", width: "16px", height: "16px" }}
              />
              Deactivate Account (isDeleted)
            </label>
          </div>

          <div style={{ marginTop: 28, display: "flex", gap: 12 }}>
            <button type="submit" className="btn btnPrimary">Save</button>
            <button type="button" onClick={() => navigate("/admin/staff")} className="btn">
              Cancel
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}
